import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"The Neuron — 2026-04-23","description":"","frontmatter":{"title":"The Neuron — 2026-04-23","date":"2026-04-23T00:00:00.000Z","source":"The Neuron","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-23-the-neuron.md","filePath":"research/ai-news/2026-04/2026-04-23-the-neuron.md","lastUpdated":1779898012000}'),n={name:"research/ai-news/2026-04/2026-04-23-the-neuron.md"};function s(i,e,p,l,m,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🧠-the-neuron-—-2026-04-23" tabindex="-1">🧠 The Neuron — 2026-04-23 <a class="header-anchor" href="#🧠-the-neuron-—-2026-04-23" aria-label="Permalink to &quot;🧠 The Neuron — 2026-04-23&quot;">​</a></h1><blockquote><p>面向非技術讀者的 AI 日報，3 分鐘讀完 來源：<a href="https://rss.beehiiv.com/feeds/N4eCstxvgX.xml" target="_blank" rel="noreferrer">The Neuron</a></p></blockquote><hr><h2 id="😺-live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" tabindex="-1"><a href="https://www.theneurondaily.com/p/live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">😺 LIVE NOW: GPT 5.5 (The Spud Model??) Just Dropped. Let&#39;s Break It.</a> <a class="header-anchor" href="#😺-live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" aria-label="Permalink to &quot;[😺 LIVE NOW: GPT 5.5 (The Spud Model??) Just Dropped. Let&#39;s Break It.](https://www.theneurondaily.com/p/live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-04-23</em></p><p><a href="https://www.youtube.com/live/I3sU4JmLR3k?si=McUbfgZ-QmXnk78w&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer"></a></p><p>Click the image above to watch LIVE on YouTube right now!</p><p>Welcome, humans.</p><p><a href="https://openai.com/index/introducing-gpt-5-5/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">GPT 5.5 (Spud) is LIVE</a>… and so are we! <a href="https://www.youtube.com/live/I3sU4JmLR3k?si=MDAr18UzSgW-fYoy&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">Come join by clicking here</a> &amp; ask your questions!</p><p><a href="https://www.youtube.com/live/I3sU4JmLR3k?si=McUbfgZ-QmXnk78w&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer"></a></p><p>No time for thumbnails, so click this image that is representation of Corey and myself to come hang on YouTube</p><p>Context: This shipped one week after <a href="https://www.anthropic.com/news/claude-opus-4-7?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">Anthropic shipped Claude Opus 4.7</a>. The one-line summary: both labs now sell &quot;worker models&quot; — AI built to finish your work, not chat with you. The benchmark scoreboard just got wild, and the pricing gap widened.</p><p>Grant and <a href="https://www.linkedin.com/in/coreynoles?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">Corey Noles</a> hit record the same afternoon <a href="https://openai.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">OpenAI</a> launched GPT-5.5 — a model that hit state-of-the-art 82.7% on Terminal-Bench 2.0 and 84.9% wins-or-ties against industry professionals on GDPval (OpenAI&#39;s benchmark for real knowledge work across 44 occupations).</p><p>In our<a href="https://www.youtube.com/live/I3sU4JmLR3k?si=McUbfgZ-QmXnk78w&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer"> live podcast episode</a>, Grant and Corey break down what&#39;s actually new, where OpenAI beats Anthropic (and vice versa), and whether GPT-5.5 Pro at $30/$180 per million tokens is worth 6x the cost of GPT-5.4.</p><p><a href="https://theneuron.ai/explainer-articles/-openai-launched-gpt-55-and-its-built-to-run-your-computer/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">Here’s our brief TL;DR write-up on the website; check it out here. </a></p><p>One more before you go:</p><p>A few weeks ago we went live with the <a href="https://www.youtube.com/live/QbFU0UNMVaU?si=YRpR8raOXHvfrBqw&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">&quot;AI for Total Beginners&quot; 5-Level Starter Stack</a>, a full framework for going from &quot;I&#39;ve never touched AI&quot; to &quot;AI saves me 10 hours a week.&quot; No coding required. It&#39;s at 5,700+ views and counting.</p><p>Last thing: And if you <a href="https://www.youtube.com/@theneuronai?sub_confirmation=1&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">haven’t subscribed yet, please do!</a> Click the image below to go to our channel and hit “subscribe” to get notified right when new videos go live.</p><p><a href="https://www.youtube.com/@theneuronai?sub_confirmation=1&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer"></a></p><p>We have a goal to hit 50K subscribers by the end of the year (if not 100K), and we’re basically ~30K away! If you like learning about AI, and already watch some of our videos, <a href="https://www.youtube.com/@theneuronai?sub_confirmation=1&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">do us a favor and click here to subscribe</a> today.</p><p>Stay curious,</p><p>The Neuron Team</p><p>That’s all for today, for more AI treats, check out our <a href="https://www.theneuron.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=live-now-gpt-5-5-the-spud-model-just-dropped-let-s-break-it" target="_blank" rel="noreferrer">website</a>.</p><p>P.P.S: Love the newsletter, but don’t want to receive these podcast announcement emails? Don’t unsubscribe — <a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=podcast-first-major-ai-incident-this-year-ceo-warns&amp;_bhlid=1d073d4088b90ea4abf69ef7cc157e0659ada818" target="_blank" rel="noreferrer">adjust your preferences to opt out of them here instead</a>.</p><hr><h2 id="😺-sony-s-new-robot-can-beat-professional-ping-pong-players" tabindex="-1"><a href="https://www.theneurondaily.com/p/sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">😺 Sony&#39;s new robot can beat professional ping pong players</a> <a class="header-anchor" href="#😺-sony-s-new-robot-can-beat-professional-ping-pong-players" aria-label="Permalink to &quot;[😺 Sony&#39;s new robot can beat professional ping pong players](https://www.theneurondaily.com/p/sony-s-new-robot-can-beat-professional-ping-pong-players)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-04-23</em></p><p><a href="https://www.gladly.ai/events/gladly-connect-live-2026/?utm_source=neuron&amp;utm_medium=content-syndication&amp;utm_campaign=parent-05-2026-event-gladly-connect-live-26&amp;utm_content=neuron" target="_blank" rel="noreferrer"></a></p><p>Welcome, humans</p><p>Anthropic had a rough 24 hours. Yesterday afternoon, <a href="https://x.com/TheGeorgePu?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">George Pu noticed</a> that Claude Code had quietly disappeared from the $20/mo Pro plan on Anthropic&#39;s public pricing page, pushing new users straight to the $100/mo Max tier. The post hit 4.9 million views.</p><p>Anthropic&#39;s Head of Growth, <a href="https://x.com/TheAmolAvasare?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Amol Avasare, showed up on X</a> to clarify that only 2% of new &quot;prosumer&quot; signups were actually affected and that existing Pro and Max subscribers would not lose Claude Code.</p><p>Anthropic has been doing some fishy business. <a href="https://x.com/TheAmolAvasare?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">This thread</a> more or less explains it: they released their current subscription plans before the existence of all these new features (Cowork, Claude Code, Managed Agents, etc) and the plans don&#39;t make financial sense in that setting. They were meant to provide compute for unlimited chats, not agents that code 24/7.</p><p>Reaction was swift and unkind. <a href="https://simonwillison.net/2026/Apr/22/claude-code-confusion/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Simon Willison</a> and legendary AI player hater Ed Zitron pointed out that the change had propagated to the public pricing page, support docs, AND help center; that&#39;s not what a genuine 2% experiment actually looks like. <a href="https://x.com/GergelyOrosz?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Gergely Orosz</a> called it a &quot;fake-door test&quot; and flagged the obvious tension with a company that pitches &quot;safety and integrity&quot; as core values. Sam Altman quote-tweeted the whole saga with two words: <a href="https://x.com/sama/status/2046808114561974567?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">&quot;ok boomer.&quot;</a> Anthropic reverted the pricing page within a few hours, though as Simon noted, &quot;the experiment is still running, just not visible to the rest of the world.&quot;</p><p>All right, enough of this. I&#39;ve decided (on behalf of Anthropic) that the only solution to survive this current moment, and win back the good will of the people (power users), is to release an open source distilled version of Opus 4.6. It&#39;s the only way to crush demand on your subscription services and get back some of your compute.</p><p>Here’s how you do it:</p><p>Anthropic being Anthropic, you can’t just give it away for free, so you sell a one-time license to download it, like old school software used to get sold.</p><p>You sell it both out of the box (self hosted) and offer a managed hosted version of it through new Daddy Warbucks AWS for a flat rate per hour like other hosted GPUs.</p><p>You get all your power users and devs to move to this new plan type (self-hosted distilled / managed distilled), and you keep $20 pro and $100-200 Max tiers in tact for the power normies and hobbyists.</p><p>Next time you launch some cool new feature, just make a new plan for it. So sayeth the first commandment of the Marketing Bible 101: The Lord giveth, but he better not taketh away, or we be big mad.</p><p>Boom. Fixed this for y’all. Do this playbook, and six months, you’ll IPO into the rarified trillion dollar company atmosphere born anew. Don’t say we at The Neuron never did nothing for ya. Also, our emails are open if you want more of our genius biz moves.</p><p>Here’s what happened in AI today:</p><p>😺 Google and OpenAI both shipped agents to own your team&#39;s workflow.</p><p>📰 OpenAI&#39;s new ChatGPT for Clinicians reportedly beats physicians on a new benchmark.</p><p>📰 Meta started recording US employee keystrokes to train its agents.</p><p>🍪 Xiaomi dropped MiMo-V2.5, with 1M context and native multimodal.</p><p>🧩 Sony&#39;s Ace robot just dethroned elite human ping-pong pros</p><p>… <a href="https://theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-wednesday-april-22-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">and a whole lot more that you can read about here</a>.</p><p>😺 Sony&#39;s Ace is the first ping-pong robot that actually beats elite humans.</p><p>DEEP DIVE: <a href="https://theneuron.ai/explainer-articles/sony-built-the-first-robot-to-beat-elite-ping-pong-players/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">All About How the Ping Pong Robot Works</a></p><p>For 43 years, scientists have been trying to perfect the perfect ping-pong bot. But all the previous papers came with asterisks: shrunken courts, modified rackets, or bots with serves or spin. Also known as: me playing (sad).</p><p>Well, a <a href="https://www.nature.com/articles/s41586-026-10338-5?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Nature cover paper today</a> from Sony AI comes with none of the above. Meet Ace, the ultimate ping pong bot. Your friend who had the basement table would be sent home crying. Take that, Billy! Finally! My ultimate revenge!</p><p>Here’s what happened:</p><p>The matches. Under full <a href="https://www.ittf.com?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">ITTF rules</a> (the official International Table Tennis Federation rulebook, same one pros use at the Olympics) on an Olympic-size court (~14m × 7m, way bigger than the table in Billy’s basement) inside Sony&#39;s Tokyo HQ, Ace played five elite amateurs (10+ years of training) and two Japanese pros.</p><p>April 2025: 3-2 vs elites, 0-2 vs pros.</p><p><a href="https://ai.sony/news/sony-ai-announces-breakthrough-research-in-real-world-artificial-intelligence-and-robotics?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">December 2025 rematch</a>: Ace beat both elites AND one pro.</p><p>March 2026: Ace beat all three new pros at least once. The rematch tour didn&#39;t go how rematch tours are supposed to go. The underdogs got cooked.</p><p>The tech:</p><p>Nine cameras triangulate the ball (combine multiple camera angles to pin down its exact 3D position) at 200 Hz (200 snapshots per second).</p><p>Three <a href="https://ace.ai.sony?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">event-based vision cameras</a> (specialized Sony chips that only flag pixels that change brightness, instead of snapping full frames like your phone does) watch the logo printed on the ball to read how fast it&#39;s spinning.</p><p>Latency: 10.2 milliseconds (ms). About 30x faster than a human blink. Humans react in ~230 ms, meaning Ace sees the ball ten times faster than you do.</p><p>A deep reinforcement learning (RL) policy (the AI training method where a system learns by trial-and-error through millions of practice games; same family of techniques that taught AlphaGo to beat the world Go champ) trained entirely in simulation (a physics-accurate video-game version of ping-pong) drives the arm with zero fine-tuning on the real court (meaning: everything it learned came from the simulator, no practice matches required).</p><p>How it wins:</p><p>Not with power. Ace&#39;s winning shots are statistically indistinguishable from its returned shots (p=0.88; in stats, a p-value tells you how likely a result is due to random chance, so p=0.88 basically means &quot;identical&quot;).</p><p>Human winning shots are dramatically harder than their averages (p&lt;0.001, meaning &quot;basically certain there&#39;s a real difference&quot;).</p><p>Ace wins because it almost never misses, returning 75% of shots up to 450 rad/s of spin (about 72 full rotations per second while the ball&#39;s in flight). Humans have signature shots. Ace has none.</p><p>Why this matters: AI has been clearing “unsolvable” benchmarks since chess in 1997. Go, StarCraft, <a href="https://www.nature.com/articles/s41586-022-04357-9?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Gran Turismo</a> (the PlayStation racing sim), <a href="https://www.nature.com/articles/s41586-023-06419-4?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">drone racing</a> (where AI-piloted drones beat human champions on first-person-view obstacle courses). But all were digital or static. Ace is the first physical, real-time, adversarial sport (adversarial meaning a human is actively trying to beat it back, not a puzzle you solve once) under real rules. Sony AI chief scientist Peter Stone compared it to the Apollo program: &quot;not about immediate commercialization but the technologies that come out of it.&quot;</p><p>Our take: The field&#39;s grandfather isn&#39;t buying the hype. <a href="https://dnyuz.com/2026/04/22/meet-ace-the-paddle-wielding-robot-who-just-beat-humans-at-ping-pong-in-ai-breakthrough/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">John Billingsley</a>, who co-ran the first robot ping-pong contests in 1983, told the AP that Sony &quot;went at the task mob-handed (British slang for throwing overwhelming numbers at one problem, like sending 30 people to do one person&#39;s job), and used sledgehammer techniques.&quot;</p><p>Nine camera eyes, a custom arm, five years of engineering: is this &quot;AI beats humans&quot; or &quot;mountain of specialized silicon beats humans&quot;? Now, for the optimistic read: as 1992 Olympian <a href="https://www.nature.com/articles/s41586-026-10338-5?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Kinjiro Nakamura</a> said watching Ace play: &quot;I didn&#39;t think it was possible. But the fact that it was possible... means a human could do it too.&quot;</p><p>Gotta love the human spirit!</p><p>FROM OUR PARTNERS</p><p>AI Beyond the Pilot Phase</p><p><a href="https://www.gladly.ai/events/gladly-connect-live-2026/?utm_source=neuron&amp;utm_medium=content-syndication&amp;utm_campaign=parent-05-2026-event-gladly-connect-live-26&amp;utm_content=neuron" target="_blank" rel="noreferrer"></a></p><p>AI has everyone talking. Not everyone has answers. At Gladly Connect Live, CX leaders from Condé Nast, Smith Optics, and more share exactly how they moved AI from pilot to production, the timeline, the systems, the QA loops. 13+ sessions built for the moment we&#39;re all in. For CX and ecommerce leaders. Atlanta, May 4–6. Space is limited, secure your spot now.</p><p><a href="https://www.gladly.ai/events/gladly-connect-live-2026/?utm_source=neuron&amp;utm_medium=content-syndication&amp;utm_campaign=parent-05-2026-event-gladly-connect-live-26&amp;utm_content=neuron" target="_blank" rel="noreferrer">Register now</a></p><p>🎓 AI Skill of the Day: The Fable Prompt</p><p>The problem with learning hard concepts from AI: you read a definition, you nod, you close the tab, and by Tuesday, you remember nothing.<a href="https://x.com/AmandaAskell?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> Amanda Askell</a> (Anthropic&#39;s in-house philosopher, who works on Claude&#39;s character and values) shared a prompt in a recent interview that fixes this. She uses it to explore whatever academic field she&#39;s curious about that week.</p><p>The trick: instead of asking Claude to explain the concept, ask it to write a fable that embodies the concept, with the reveal saved for the end. Your brain processes story way more durably than definitions. By the time the punchline lands, you&#39;ve already built intuition for the idea.</p><p>Pick any field (philosophy, economics, quantum mechanics, evolutionary biology, linguistics, or any old random thing you wanna learn). Then drop it into the prompt below.</p><p>I want you to select a concept at about the graduate-student level from the field of [YOUR FIELD HERE]. Then indirectly explain this concept completely by writing a fable. Structure it so that only toward the very end do readers gradually realize what the concept actually is. After the story, add a section that clearly articulates the concept you just conveyed.</p><p>As an example, try it with game theory and watch how much harder &quot;Nash equilibrium&quot; hits when three merchants in a village discover it the hard way.</p><p>Want more tips like this? Check out our<a href="https://www.theneuron.ai/explainer-articles/april-ai-skill-of-the-day-week-4-your-requests-answered/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> new AI Skill of the Day Digest for April</a>.</p><p>Treats to Try</p><p>*Asterisk = from our partners (only the first one!). <a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Advertise to 700K+ readers here</a>!</p><p>*<a href="https://marketingagainstthegrain.com/subscribe?utm_source=the_neuron&amp;utm_medium=email&amp;utm_campaign=partnership&amp;utm_content=cross_promo&amp;utm_term=2026" target="_blank" rel="noreferrer">Turn AI knowledge into better marketing</a>. Marketing Against the Grain delivers real campaign breakdowns, honest data, and AI-assisted playbooks from marketers actively running growth at scale. <a href="https://marketingagainstthegrain.com/subscribe?utm_source=the_neuron&amp;utm_medium=email&amp;utm_campaign=partnership&amp;utm_content=cross_promo&amp;utm_term=2026" target="_blank" rel="noreferrer">Subscribe today</a>.</p><p><a href="https://openai.com/index/introducing-workspace-agents-in-chatgpt/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">OpenAI</a> launched Workspace Agents in ChatGPT: five Codex-powered templates (Software Reviewer, Product Feedback Router, Weekly Metrics Reporter, Lead Outreach, Third-Party Risk Manager) deployable to ChatGPT or Slack, free until May 6 then metered (<a href="https://www.theneuron.ai/explainer-articles/openais-agent-week-workspace-agents-codex-for-almost-everything-and-images-20/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">our full coverage here</a>).</p><p><a href="https://mimo.xiaomi.com/mimo-v2-5-pro/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Xiaomi MiMo-V2.5-Pro</a> entered public beta with native vision and audio, a 1-million-token context window (roughly 1,500 pages in one chat), and 40-60% better token efficiency on long-horizon agent tasks; API is live now, open weights planned soon —paid API,<a href="https://platform.xiaomimimo.com/token-plan?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> free TTS tier for now</a>.</p><p><a href="https://huggingface.co/Qwen/Qwen3.6-27B?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Qwen3.6-27B</a> is Alibaba&#39;s new dense 27-billion-parameter open model that scores 77.2 on SWE-bench Verified (a benchmark of real GitHub bug-fix tasks) and runs on consumer GPUs via<a href="https://huggingface.co/unsloth/Qwen3.6-27B-GGUF?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> Unsloth&#39;s GGUF quantizations</a> (compressed versions for slower hardware);<a href="https://simonwillison.net/2026/Apr/22/qwen36-27b/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> Simon Willison&#39;s review</a> has local benchmarks —free (open weights).</p><p><a href="https://openai.com/index/introducing-openai-privacy-filter/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">OpenAI&#39;s Privacy Filter</a> is a new open-weight 1.5B-parameter model that detects and redacts personal info (names, addresses, passwords, API keys; 8 categories) with 96%+ accuracy, runs locally (<a href="https://github.com/openai/privacy-filter?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">GitHub</a>) —free to try.</p><p><a href="https://www.mythoswatch.org/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">MythosWatch</a> tracks who officially has access to Anthropic&#39;s unreleased Mythos cybersecurity model: a live public ledger of 51+ governments, regulators, and banks, updated as disclosures happen —free to track.</p><p><a href="https://www.brex.com/crabtrap?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Brex CrabTrap</a> sits in front of your production AI agents as an open-source proxy, inspecting every outbound request with an LLM-as-a-judge (another model grading what your agent wants to do), and blocking risky actions before they hit external APIs —free and open source.</p><p>Around the Horn</p><p><a href="https://www.reddit.com/r/aivideo/comments/1sqwzwj/breaking_bad_by_balenciaga_2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"></a></p><p><a href="https://x.com/thekaransinghal/status/2047091103170785324?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">OpenAI</a> launched ChatGPT for Clinicians (free for verified US physicians) alongside HealthBench Professional, a new 1,500+ conversation benchmark where GPT-5.4 reportedly outperformed specialty-matched physicians given unbounded time and web access; 7,000 pre-launch test conversations, 99.6% rated safe and accurate.</p><p><a href="https://www.cnbc.com/2026/04/22/meta-tracks-employee-usage-on-google-linkedin-ai-training-project.html?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Meta</a> rolled out its &quot;Model Capability Initiative,&quot; tracking US employee keystrokes, mouse movements, and screen content on Google, LinkedIn, Wikipedia, GitHub, and Slack to train AI agents on real office work; internal backlash called it &quot;dystopian&quot; and there&#39;s no opt-out.</p><p><a href="https://www.theguardian.com/technology/2026/apr/22/anthropic-investigates-report-of-rogue-access-to-hack-enabling-mythos-ai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Anthropic</a> is investigating a report that its unreleased Mythos cybersecurity model (capable of advanced attack simulation) was accessed without authorization via a third-party vendor.</p><p><a href="https://theneuron.ai/explainer-articles/google-came-to-cloud-next-26-with-the-full-stack?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Google&#39;s Cloud Next &#39;26</a> went all-in on &quot;Agentic Enterprise&quot;: Gemini Enterprise Agent Platform for governing thousands of agents, Workspace Intelligence (a semantic layer across Gmail/Docs/Drive/Chat), eighth-gen TPU 8t and 8i chips, and 40% QoQ growth in paid Gemini Enterprise seats. Danfoss automated 80% of email order processing; Macquarie Bank claims 100K team hours saved.</p><p><a href="https://www.theguardian.com/us-news/2026/apr/22/pentagon-asks-for-54bn-in-pivot-towards-ai-powered-war?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">The Pentagon</a> requested a $54B FY2027 budget for autonomous drone warfare, the largest single commitment to AI-powered war in history; experts warned the US lacks doctrine for deploying lethal autonomous swarms.</p><p>Economist Pedro Serôdio published a<a href="https://britishprogress.org/reports/ai-and-the-uk-labour-market-the-evidence-so-far?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer"> counter-narrative</a> to AI’s job impact: three years after ChatGPT, UK employment data across 412 occupations shows zero visible difference between roles most and least exposed to AI; adoption sits at just 2.1% of all work tasks, and Robert Solow&#39;s 1987 line applies (electricity took 40 years to show up in the productivity stats).</p><p><a href="https://theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-wednesday-april-22-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">Want absolutely EVERYTHING that happened in AI this week? Click here!</a></p><p>FROM OUR PARTNERS</p><p>Are you tracking agent views on your docs?</p><p><a href="https://www.mintlify.com/use-cases/developer-documentation/?utm_campaign=&amp;utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_content=AI%20traffic%2C%20Mar%20-%20Secondary&amp;_bhiiv=opp_0bf3c063-fda2-42ca-a69b-dd2513f9051c_71696469&amp;bhcl_id=b2f34542-e430-46c4-afb0-bbeb3e97262d__" target="_blank" rel="noreferrer"></a></p><p>AI agents already outnumber human visitors to your docs — now you can track them.</p><p><a href="https://www.mintlify.com/use-cases/developer-documentation/?utm_campaign=&amp;utm_source=beehiiv&amp;utm_medium=newsletter&amp;utm_content=AI%20traffic%2C%20Mar%20-%20Secondary&amp;_bhiiv=opp_0bf3c063-fda2-42ca-a69b-dd2513f9051c_71696469&amp;bhcl_id=b2f34542-e430-46c4-afb0-bbeb3e97262d__" target="_blank" rel="noreferrer">See your AI traffic!</a></p><p>Thursday Trivia</p><p>You know the drill: One is AI, and one is real. Which is which? Vote below!</p><p>A.</p><p>TBH this is not far off from what my page looked like back then</p><p>B.</p><p>A Cat’s Commentary</p><p>Trivia answer: A <a href="https://www.reddit.com/r/ChatGPT/comments/1ssbsfj/2008_myspace_profile/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players#lightbox" target="_blank" rel="noreferrer">is AI</a>, and B is real.</p><p>That’s all for now.</p><p>P.P.S: Love the newsletter, but only want to get it once per week? Don’t unsubscribe—<a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=sony-s-new-robot-can-beat-professional-ping-pong-players" target="_blank" rel="noreferrer">update your preferences here</a>.</p><hr>',114)])])}const d=t(n,[["render",s]]);export{c as __pageData,d as default};
